import React from 'react';
import { Card, Stack, Text, Heading, Divider } from '@ggui-ai/design/primitives';

interface Props {
  /** City name */
  city: string;
  /** Current temperature */
  temperature: number;
  /** Weather condition (Sunny, Cloudy, Rainy, etc.) */
  condition: string;
  /** Humidity percentage */
  humidity: number;
  /** Wind speed */
  windSpeed: number;
  /** Temperature unit (C or F) */
  unit?: string;
  /** 5-day forecast array */
  forecast: Array<{ day?: string; icon?: string; high?: number; low?: number }>;
}

export default function GeneratedComponent(props: Props) {
  const {
    city,
    temperature,
    condition,
    humidity,
    windSpeed,
    unit = 'C',
    forecast = [],
  } = props;

  return (
    <Card 
      shadow="md" 
      padding={24} 
      radius="lg" 
      style={{ backgroundColor: 'var(--ggui-color-surface)' }}
    >
      <Stack gap={24}>
        {/* Header Section */}
        <Stack gap={4}>
          <Heading level={2} color="var(--ggui-color-onSurface)">
            {city ?? 'Unknown City'}
          </Heading>
          <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">
            Current Conditions
          </Text>
        </Stack>

        {/* Current Weather */}
        <Stack direction="horizontal" align="center" justify="between">
          <Heading level={1} color="var(--ggui-color-primary-600)">
            {temperature ?? 0}°{unit}
          </Heading>
          <Text variant="bodyLarge" weight="semibold" color="var(--ggui-color-onSurface)">
            {condition ?? 'N/A'}
          </Text>
        </Stack>

        {/* Details */}
        <Stack direction="horizontal" gap={16}>
          <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
            Humidity: {humidity ?? 0}%
          </Text>
          <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
            Wind: {windSpeed ?? 0} km/h
          </Text>
        </Stack>

        <Divider margin={8} color="var(--ggui-color-outlineVariant)" />

        {/* 5-Day Forecast */}
        <Stack direction="horizontal" justify="between" gap={8}>
          {forecast.map((item, index) => (
            <Stack key={index} align="center" gap={4}>
              <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">
                {item.day ?? '---'}
              </Text>
              <Text size="2xl" aria-label={item.icon ?? 'weather icon'}>
                {item.icon ?? '☁️'}
              </Text>
              <Stack direction="horizontal" gap={4}>
                <Text variant="caption" weight="semibold" color="var(--ggui-color-onSurface)">
                  {item.high ?? '--'}°
                </Text>
                <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
                  {item.low ?? '--'}°
                </Text>
              </Stack>
            </Stack>
          ))}
        </Stack>
      </Stack>
    </Card>
  );
}

import React, { useState, useMemo } from 'react';
import {
  Container,
  Box,
  Stack,
  Text,
  Heading,
  Input,
  Card,
  Divider,
} from '@ggui-ai/design/primitives';

interface Props {
  elements: Array<{
    atomicNumber?: number;
    symbol?: string;
    name?: string;
    atomicWeight?: number;
    category?: string;
    row?: number;
    col?: number;
  }>;
}

const getCategoryColor = (category?: string) => {
  switch (category) {
    case 'noble-gas':
      return 'var(--ggui-color-info-200, #a5f3fc)';
    case 'nonmetal':
      return 'var(--ggui-color-success-100, #dcfce7)';
    case 'halogen':
      return 'var(--ggui-color-warning-100, #fef3c7)';
    default:
      return 'var(--ggui-color-primary-50, #f0f9ff)';
  }
};

export default function GeneratedComponent(props: Props) {
  const [search, setSearch] = useState('');
  const [selected, setSelected] = useState<Props['elements'][0] | null>(null);

  const filteredElements = useMemo(() => {
    const s = search.toLowerCase();
    return props.elements.filter(
      (e) =>
        e.name?.toLowerCase().includes(s) ||
        e.symbol?.toLowerCase().includes(s)
    );
  }, [search, props.elements]);

  const categories = useMemo(() => {
    const unique = Array.from(
      new Set(props.elements.map((e) => e.category).filter(Boolean))
    );
    return unique as string[];
  }, [props.elements]);

  return (
    <Container maxWidth="full" padding="var(--ggui-spacing-6, 24px)">
      <Stack gap="var(--ggui-spacing-6, 24px)">
        <Box>
          <Heading level={2}>Periodic Table</Heading>
          <Box paddingY="var(--ggui-spacing-4, 16px)">
            <Input
              label="Search Elements"
              placeholder="Search by name or symbol..."
              value={search}
              onChange={setSearch}
            />
          </Box>
        </Box>

        <div
          style={{
            display: 'grid',
            gridTemplateColumns: 'repeat(18, 1fr)',
            gap: 'var(--ggui-spacing-1, 4px)',
            alignItems: 'start',
          }}
          aria-label="Periodic Table"
        >
          {props.elements.map((el) => {
            const isMatch =
              search === '' ||
              filteredElements.some((m) => m.atomicNumber === el.atomicNumber);
            return (
              <Box
                key={el.atomicNumber ?? 0}
                style={{
                  gridRow: el.row,
                  gridColumn: el.col,
                  opacity: isMatch ? 1 : 0.3,
                  transition: 'opacity 200ms ease, background-color 200ms ease',
                }}
                background={getCategoryColor(el.category)}
                padding="var(--ggui-spacing-2, 8px)"
                borderRadius="var(--ggui-shape-radius-sm, 4px)"
              >
                <button
                  type="button"
                  aria-label={`Element: ${el.name}, Atomic Number: ${el.atomicNumber}`}
                  onClick={() => setSelected(el)}
                  style={{
                    all: 'unset',
                    width: '100%',
                    textAlign: 'center',
                    cursor: 'pointer',
                  }}
                >
                  <Text size="xs">{el.atomicNumber}</Text>
                  <Heading level={4}>{el.symbol}</Heading>
                </button>
              </Box>
            );
          })}
        </div>

        <Stack
          direction="horizontal"
          gap="var(--ggui-spacing-4, 16px)"
          justify="center"
          wrap
        >
          {categories.map((cat) => (
            <Stack
              key={cat}
              direction="horizontal"
              gap="var(--ggui-spacing-2, 8px)"
              align="center"
            >
              <Box
                background={getCategoryColor(cat)}
                borderRadius="var(--ggui-shape-radius-sm, 4px)"
                padding="var(--ggui-spacing-2, 8px)"
                style={{ width: '16px', height: '16px' }}
              />
              <Text variant="caption" style={{ textTransform: 'capitalize' }}>
                {cat}
              </Text>
            </Stack>
          ))}
        </Stack>

        {selected && (
          <Card padding="var(--ggui-spacing-6, 24px)" radius="lg">
            <Stack gap="var(--ggui-spacing-3, 12px)">
              <Heading level={3}>{selected.name}</Heading>
              <Divider />
              <Stack gap="var(--ggui-spacing-1, 4px)">
                <Text>
                  <strong>Symbol:</strong> {selected.symbol}
                </Text>
                <Text>
                  <strong>Atomic Number:</strong> {selected.atomicNumber}
                </Text>
                <Text>
                  <strong>Atomic Weight:</strong> {selected.atomicWeight}
                </Text>
                <Text style={{ textTransform: 'capitalize' }}>
                  <strong>Category:</strong> {selected.category}
                </Text>
              </Stack>
              <Box paddingY="var(--ggui-spacing-2, 8px)">
                <button
                  type="button"
                  onClick={() => setSelected(null)}
                  style={{
                    cursor: 'pointer',
                    background: 'none',
                    border: 'none',
                    padding: 0,
                    color: 'var(--ggui-color-primary-600, #0284c7)',
                  }}
                >
                  <Text variant="bodySmall">Clear Selection</Text>
                </button>
              </Box>
            </Stack>
          </Card>
        )}
      </Stack>
    </Container>
  );
}

import React, { useState, useEffect } from 'react';
import {
  Container,
  Card,
  Stack,
  Box,
  Divider,
  Text,
  Heading,
  Button,
  Input,
  Select,
  Toggle,
  RadioGroup,
  Progress,
} from '@ggui-ai/design/primitives';

interface Props {
  initialProfile?: {
    name?: string;
    email?: string;
    avatar?: string;
    role?: string;
    emailNotifications?: boolean;
    theme?: string;
  };
  avatarOptions: string[];
  roleOptions: string[];
  onComplete: (data: any) => void;
}

export default function GeneratedComponent(props: Props) {
  const [step, setStep] = useState(1);
  const [formData, setFormData] = useState({
    name: props.initialProfile?.name ?? '',
    email: props.initialProfile?.email ?? '',
    avatar: props.initialProfile?.avatar ?? (props.avatarOptions[0] ?? ''),
    role: props.initialProfile?.role ?? (props.roleOptions[0] ?? ''),
    emailNotifications: props.initialProfile?.emailNotifications ?? false,
    theme: props.initialProfile?.theme ?? 'light',
  });

  useEffect(() => {
    const handleAgentData = (event: any) => {
      if (event.detail) {
        setFormData((prev) => ({ ...prev, ...event.detail }));
      }
    };
    window.addEventListener('ggui:agent-data', handleAgentData as EventListener);
    return () => window.removeEventListener('ggui:agent-data', handleAgentData as EventListener);
  }, []);

  const validateStep1 = () => {
    const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
    return formData.name.trim().length > 0 && emailRegex.test(formData.email);
  };

  const isNextDisabled = step === 1 ? !validateStep1() : false;

  return (
    <Container maxWidth="md" padding="var(--ggui-spacing-6)">
      <Card padding="var(--ggui-spacing-6)" shadow="md" border={true} radius="lg">
        <Stack gap="var(--ggui-spacing-6)">
          <Stack gap="var(--ggui-spacing-2)">
            <Heading level={3}>Step {step} of 3</Heading>
            <Progress value={(step / 3) * 100} size="md" />
          </Stack>

          <Box style={{ animation: 'ggui-fadeIn 200ms ease-out' }}>
            {step === 1 && (
              <Stack gap="var(--ggui-spacing-4)">
                <Input
                  label="Name"
                  value={formData.name}
                  onChange={(v) => setFormData({ ...formData, name: v })}
                  required
                />
                <Input
                  label="Email"
                  type="email"
                  value={formData.email}
                  onChange={(v) => setFormData({ ...formData, email: v })}
                  required
                />
                <Stack gap="var(--ggui-spacing-2)">
                  <Text variant="label">Select Avatar</Text>
                  <Stack direction="horizontal" gap="var(--ggui-spacing-2)">
                    {props.avatarOptions.map((opt) => (
                      <Button
                        key={opt}
                        variant={formData.avatar === opt ? 'primary' : 'outline'}
                        onClick={() => setFormData({ ...formData, avatar: opt })}
                        aria-label={`Select avatar ${opt}`}
                      >
                        {opt}
                      </Button>
                    ))}
                  </Stack>
                </Stack>
              </Stack>
            )}

            {step === 2 && (
              <Stack gap="var(--ggui-spacing-4)">
                <Select
                  label="Role"
                  value={formData.role}
                  onChange={(v) => setFormData({ ...formData, role: v })}
                  options={props.roleOptions.map((r) => ({ value: r, label: r }))}
                />
                <Toggle
                  label="Email Notifications"
                  checked={formData.emailNotifications}
                  onChange={(v) => setFormData({ ...formData, emailNotifications: v })}
                />
                <RadioGroup
                  label="Theme"
                  value={formData.theme}
                  onChange={(v) => setFormData({ ...formData, theme: v })}
                  options={[
                    { value: 'light', label: 'Light' },
                    { value: 'dark', label: 'Dark' },
                  ]}
                />
              </Stack>
            )}

            {step === 3 && (
              <Stack gap="var(--ggui-spacing-4)">
                <Heading level={4}>Review Information</Heading>
                <Divider />
                <Stack gap="var(--ggui-spacing-2)">
                  <Text><strong>Name:</strong> {formData.name}</Text>
                  <Text><strong>Email:</strong> {formData.email}</Text>
                  <Text><strong>Avatar:</strong> {formData.avatar}</Text>
                  <Text><strong>Role:</strong> {formData.role}</Text>
                  <Text><strong>Notifications:</strong> {formData.emailNotifications ? 'Enabled' : 'Disabled'}</Text>
                  <Text><strong>Theme:</strong> {formData.theme}</Text>
                </Stack>
              </Stack>
            )}
          </Box>

          <Stack direction="horizontal" justify="between">
            <Button
              variant="ghost"
              disabled={step === 1}
              onClick={() => setStep(step - 1)}
            >
              Back
            </Button>
            {step < 3 ? (
              <Button disabled={isNextDisabled} onClick={() => setStep(step + 1)}>
                Next
              </Button>
            ) : (
              <Button variant="primary" onClick={() => props.onComplete(formData)}>
                Complete Setup
              </Button>
            )}
          </Stack>
        </Stack>
      </Card>
    </Container>
  );
}

