// Path: /virtual/hooks.ts
import type { Props, HookReturn } from '/virtual/types';
import * as constants from '/virtual/constants';
// hooks.ts — state, handlers, data transformations
import { useState, useEffect, useMemo, useCallback, useRef } from 'react';

export function useComponent(props: Props): HookReturn {

  const displayUnit = useMemo(() => {
    return props.unit === 'Fahrenheit' ? '°F' : '°C';
  }, [props.unit]);

  const windUnit = useMemo(() => {
    return props.unit === 'Fahrenheit' ? 'mph' : 'km/h';
  }, [props.unit]);

  const formatted = useMemo(() => {
    const condition = (props.condition || '').toLowerCase();
    const iconMap: Record<string, string> = {
      sunny: '☀️',
      cloudy: '☁️',
      rainy: '🌧️',
      stormy: '⛈️',
      snowy: '❄️',
    };

    return {
      tempDisplay: `${Math.round(props.temperature)}${displayUnit}`,
      humidityDisplay: `${props.humidity}%`,
      windDisplay: `${props.windSpeed}${windUnit}`,
      conditionIcon: iconMap[condition] || '🌡️',
    };
  }, [props.temperature, props.humidity, props.windSpeed, props.condition, displayUnit, windUnit]);

  return {
    formatted,
    forecastItems: props.forecast,
    displayUnit,
  };
}


