/**
 * Helper function to provide distinct colors for each element category.
 * Using design system tokens to ensure theme compatibility.
 */
const getCategoryColor = (category: string) => {
  const cat = category.toLowerCase();
  if (cat.includes('noble gas')) return 'var(--ggui-color-primary-200, #bae6fd)';
  if (cat.includes('alkali metal')) return 'var(--ggui-color-error, #dc2626)';
  if (cat.includes('alkaline earth metal')) return 'var(--ggui-color-warning, #d97706)';
  if (cat.includes('transition metal')) return 'var(--ggui-color-primary-500, #0ea5e9)';
  if (cat.includes('post-transition metal')) return 'var(--ggui-color-success, #16a34a)';
  if (cat.includes('metalloid')) return 'var(--ggui-color-info, #0284c7)';
  if (cat.includes('nonmetal')) return 'var(--ggui-color-primary-700, #0369a1)';
  if (cat.includes('lanthanide')) return 'var(--ggui-color-primary-300, #7dd3fc)';
  if (cat.includes('actinide')) return 'var(--ggui-color-primary-100, #e0f2fe)';
  return 'var(--ggui-color-outline, #d4d4d8)';
};

export const Legend: React.FC<LegendProps> = ({ categories }) => {
