import React from 'react';
import { Box, Text } from '@ggui-ai/design/primitives';
import { ElementCellProps } from '/virtual/types';

/**
 * Returns a CSS color variable based on the element's chemical category.
 * Using provided design system tokens with appropriate fallbacks.
 */
const getCategoryColor = (category: string): string => {
  const normalized = category.toLowerCase();

  if (normalized.includes('alkali metal')) return 'var(--ggui-color-primary-100, #f0f9ff)';
  if (normalized.includes('alkaline earth metal')) return 'var(--ggui-color-primary-200, #e0f2fe)';
  if (normalized.includes('transition metal')) return 'var(--ggui-color-outlineVariant, #f4f4f5)';
  if (normalized.includes('post-transition metal')) return 'var(--ggui-color-success-100, #dcfce7)';
  if (normalized.includes('metalloid')) return 'var(--ggui-color-warning-100, #fef3c7)';
  if (normalized.includes('noble gas')) return 'var(--ggui-color-secondary-100, #ede9fe)';
  if (normalized.includes('nonmetal')) return 'var(--ggui-color-success-200, #bbf7d0)';
  if (normalized.includes('lanthanide')) return 'var(--ggui-color-info-100, #cffafe)';
  if (normalized.includes('actinide')) return 'var(--ggui-color-container, #ede9fe)';

  return 'var(--ggui-color-surfaceVariant, #f4f4f5)';
};

/**
 * ElementCell component represents a single element in the periodic table grid.
 * Handles grid placement, category-based coloring, and selection states.
 */
export const ElementCell: React.FC<ElementCellProps> = ({
  element,
  isSelected,
  onSelect,
  isMatch
}) => {
  const [isHovered, setIsHovered] = React.useState(false);

  // Determine visual properties based on state
  const background = getCategoryColor(element.category);
  const opacity = isMatch ? 1 : 0.3;
  const transform = isSelected ? 'scale(1.08)' : (isHovered ? 'scale(1.04)' : 'scale(1)');
  const zIndex = isSelected ? 10 : (isHovered ? 5 : 1);
  const boxShadow = isSelected || isHovered 
    ? 'var(--ggui-shape-shadow-md, 0 4px 6px -1px rgba(0,0,0,0.1))' 
    : 'none';
  const border = isSelected 
    ? '2px solid var(--ggui-color-primary-600, #0284c7)' 
    : '1px solid var(--ggui-color-outlineVariant, #e4e4e7)';

  return (
    <div
      onClick={() => onSelect(element)}
      onMouseEnter={() => setIsHovered(true)}
      onMouseLeave={() => setIsHovered(false)}
      role="button"
      tabIndex={0}
      style={{
        // Grid positioning derived from element coordinates
        gridColumn: element.col,
        gridRow: element.row,
        cursor: 'pointer',
        transition: 'transform 200ms cubic-bezier(0.4, 0, 0.2, 1), background-color 200ms ease, opacity 200ms ease, box-shadow 200ms ease',
        opacity,
        transform,
        zIndex,
        border,
        backgroundColor: background,
        borderRadius: 'var(--ggui-shape-radius-md, 8px)',
        aspectRatio: '1/1',
        display: 'flex',
        flexDirection: 'column',
        position: 'relative',
        boxShadow: boxShadow,
        overflow: 'hidden',
        userSelect: 'none'
      }}
    >
      {/* Atomic Number - Positioned at top-left using Box primitive */}
      <Box
        padding={4}
        style={{
          position: 'absolute',
          top: 0,
          left: 0
        }}
      >
        <Text variant="caption" style={{ fontSize: '10px', lineHeight: 1 }}>
          {element.atomicNumber}
        </Text>
      </Box>

      {/* Main content area containing Symbol and Name */}
      <Box
        style={{
          flex: 1,
          display: 'flex',
          flexDirection: 'column',
          alignItems: 'center',
          justifyContent: 'center',
          padding: 'var(--ggui-spacing-2, 8px)',
          textAlign: 'center'
        }}
      >
        <Text variant="bodyLarge" weight="bold" style={{ lineHeight: 1 }}>
          {element.symbol}
        </Text>
        <Text 
          variant="caption" 
          truncate 
          style={{ fontSize: '10px', marginTop: '2px', maxWidth: '100%' }}
        >
          {element.name}
        </Text>
      </Box>
    </div>
  );
};

