const getCategoryVariant = (category: string): 'default' | 'primary' | 'secondary' | 'success' | 'warning' | 'error' | 'info' => {
  const c = category.toLowerCase();
  if (c.includes('noble')) return 'info';
  if (c.includes('alkali metal')) return 'error';
  if (c.includes('alkaline earth')) return 'warning';
  if (c.includes('transition')) return 'primary';
  if (c.includes('post-transition') || c.includes('metalloid')) return 'info';
  if (c.includes('nonmetal')) return 'success';
  if (c.includes('lanthanide') || c.includes('actinide')) return 'secondary';
  return 'default';
};

const getCategoryColor = (category: string) => {
  const c = category.toLowerCase();
  if (c.includes('noble')) return 'var(--ggui-color-info-50, #ecfeff)';
  if (c.includes('alkali metal')) return 'var(--ggui-color-error-50, #fef2f2)';
