const STEP_TITLES = ['Profile Setup', 'Preferences', 'Review'];

export const StepIndicator: React.FC<StepIndicatorProps> = ({ currentStep, totalSteps }) => {
  // Calculate the progress percentage for the bar
  const percentage = (currentStep / totalSteps) * 100;

  return (
    <Stack gap={16}>
      <Stack direction="horizontal" justify="between" align="start">
        {STEP_TITLES.map((title, index) => {
          const stepNumber = index + 1;
          const isPastOrCurrent = stepNumber <= currentStep;
          const isCurrent = stepNumber === currentStep;

          return (
            <Stack key={title} align="center" gap={8}>
              <Badge 
                variant={isPastOrCurrent ? 'primary' : 'default'} 
                pill={true}
                size="sm"
              >
                {stepNumber}
              </Badge>
              <Text
                variant="bodySmall"
                weight={isCurrent ? 'bold' : 'normal'}
                color={isCurrent ? 'var(--ggui-color-onSurface, #18181b)' : 'var(--ggui-color-onSurfaceVariant, #52525b)'}
                align="center"
              >
                {title}
              </Text>
            </Stack>
          );
        })}
      </Stack>
      <Progress value={percentage} variant="default" size="sm" />
    </Stack>
  );
};

