/**
 * State management hook for the Onboarding Wizard
 */
function useOnboarding(props: OnboardingWizardProps): UseOnboardingReturn {
  const [currentStep, setCurrentStep] = React.useState(1);
  const [formData, setFormData] = React.useState<ProfileData>({
    name: props.initialProfile?.name ?? '',
    email: props.initialProfile?.email ?? '',
    avatar: props.initialProfile?.avatar ?? '',
    role: props.initialProfile?.role ?? '',
    emailNotifications: props.initialProfile?.emailNotifications ?? true,
    theme: props.initialProfile?.theme ?? 'light',
  });

  const errors: Record<string, string> = {};
  if (currentStep === 1) {
    if (!formData.name.trim()) errors.name = 'Name is required';
    if (!formData.email.trim()) {
      errors.email = 'Email is required';
    } else if (!/^\S+@\S+\.\S+$/.test(formData.email)) {
      errors.email = 'Please enter a valid email address';
    }
    if (!formData.avatar) errors.avatar = 'Please select an avatar profile picture';
  }
  if (currentStep === 2) {
    if (!formData.role) errors.role = 'Please select your primary role';
  }

  const isValid = Object.keys(errors).length === 0;

  const updateForm = (updates: Partial<ProfileData>) => {
    setFormData(prev => ({ ...prev, ...updates }));
  };

  const nextStep = () => {
    if (isValid) setCurrentStep(s => Math.min(s + 1, 3));
  };

  const prevStep = () => {
    setCurrentStep(s => Math.max(s - 1, 1));
  };

  const submitForm = () => {
    if (isValid) props.onComplete(formData);
  };

  return {
    currentStep,
    formData,
    errors,
    isValid,
    nextStep,
    prevStep,
    updateForm,
    submitForm,
  };
}

